query:
( _view=data_volume_custom_* )
dimension ={{view}}
item={{value_filter}}
datatier = {{tier_filter}}
// remove long categories
| timeslice by {{timeslice}}

| sum(events) as events, sum(credits) as credits,sum(gbytes) as gbytes by datatier, item,_timeslice
| if (length(item) > {{max_chrs}},concat(substring(item,0,{{max_chrs}}),"..."),item) as item
| count as categories,sum(events) as events, sum(credits) as credits,sum(gbytes) as gbytes by datatier, item,_timeslice
| sum(events) as events by _timeslice,item 
| transpose row _timeslice column item
